doc.service_worker_registration:
// Service Worker registration (in sw.js)
self.addEventListener('install', function(event) {
  event.waitUntil(
    caches.open(CACHE_NAME).then(function(cache) {
      return cache.addAll(ASSETS);
    })
  );
});

// Install handler (in install-handler.js)
if (typeof InstallHandler !== 'undefined') {
  InstallHandler.init();
  InstallHandler.install();  // Trigger installation
}

// Auto-update (in auto-updater.js)
AutoUpdate.start();  // Checks GitHub every 10 minutes

